#include <vector>
#include <iostream>
#include <numeric>

using namespace std;

/**
 * @brief Calculates the score for each element in the array based on parity difference with elements to the right.
 * 
 * @param nums The input array of integers.
 * @return std::vector<long long> An array where answer[i] is the score for nums[i].
 */
std::vector<long long> solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n <= 1) {
        return std::vector<long long>(n, 0);
    }

    std::vector<long long> answer(n);

    for (int i = 0; i < n; ++i) {
        long long score = 0;
        // nums[i] parity: 0 for even, 1 for odd
        int parity_i = nums[i] % 2;

        // Count of odd and even numbers in the subarray nums[i+1...n-1]
        int count_odd_right = 0;
        int count_even_right = 0;

        for (int j = i + 1; j < n; ++j) {
            int parity_j = nums[j] % 2;
            if (parity_j == 1) { // Odd
                count_odd_right++;
            } else { // Even
                count_even_right++;
            }
        }

        // The score is the count of j > i such that parity(nums[i]) != parity(nums[j]).
        if (parity_i == 1) { // nums[i] is odd, score is the count of evens to the right
            score = count_even_right;
        } else { // nums[i] is even, score is the count of odds to the right
            score = count_odd_right;
        }

        answer[i] = score;
    }

    return answer;
}

