std::vector<long long> solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n <= 1) {
        return std::vector<long long>(n, 0);
    }

    std::vector<long long> answer(n);

    for (int i = 0; i < n; ++i) {
        long long score = 0;
        // Check j such that i < j < n
        for (int j = i + 1; j < n; ++j) {
            // Check if parity is different: (nums[i] % 2) != (nums[j] % 2)
            // This is equivalent to (nums[i] + nums[j]) % 2 != 0
            if ((nums[i] % 2) != (nums[j] % 2)) {
                score++;
            }
        }
        answer[i] = score;
    }

    return answer;
}

